class ProxyManager:
    def __init__(self):
        self.proxies = []
        self.working_proxies = []
        self.loaded = False
    
    async def fetch_all_proxies(self):
        if self.loaded:
            return len(self.proxies)
        
        print(f"🌐 Fetching proxies from {len(PROXY_SOURCES)} sources...")
        
        async with aiohttp.ClientSession() as session:
            for url in PROXY_SOURCES:
                try:
                    async with session.get(url, timeout=5) as resp:
                        content = await resp.text()
                        lines = content.splitlines()
                        for line in lines[:2000]:
                            line = line.strip()
                            if line and ':' in line and not line.startswith('#'):
                                if 'socks4' in url.lower():
                                    line = f"socks4://{line}"
                                elif 'socks5' in url.lower():
                                    line = f"socks5://{line}"
                                elif not line.startswith(('http://', 'socks')):
                                    line = f"http://{line}"
                                self.proxies.append(line)
                except:
                    pass
        
        self.proxies = list(set(self.proxies))
        self.proxies = self.proxies[:PROXY_COUNT]
        self.working_proxies = self.proxies.copy()
        self.loaded = True
        return len(self.proxies)
    
    def get_random_proxy(self):
        if self.working_proxies:
            return random.choice(self.working_proxies)
        return None
    
    def get_proxy_batch(self, count=100):
        if len(self.working_proxies) >= count:
            return random.sample(self.working_proxies, count)
        return self.working_proxies

